// 🔍 DEBUG: Zeige exakt die Eingabe-Struktur
const items = $input.all();
console.log('Anzahl Items:', items.length);
console.log('Erstes Item:', JSON.stringify(items[0], null, 2));

// Sichere Extraktion mit Fallbacks
let jsonString = '';
try {
  if (items.length > 0 && items[0] && items[0].json) {
    jsonString = items[0].json.text || items[0].json.content || '';
  }
} catch(e) {
  console.log('Fehler beim Zugriff:', e.message);
}

// ✅ Markdown-Backticks entfernen
if (jsonString) {
  jsonString = jsonString
    .replace(/```(?:json)?\s*/g, '')  // ```json oder ```
    .replace(/\s*```/g, '')           // trailing ```
    .trim();
}

// HARDCODE FALLBACK (deine ersten 5 Einträge als Backup)
const fallbackContacts = [
  {"fullName":"Atanas Alexandrov","phoneNumber":"015206916362","email":"atanas.alexandrov@posteo.de"},
  {"fullName":"Frederik Ambos","phoneNumber":"+491627960001","email":"frederik.ambos@cdp-experts.de"},
