  {"fullName":"Richard Brady","phoneNumber":"+49 89 4750 2248","email":"richard.brady@mamgruppe.com"},
  {"fullName":"Ulrich Wenzel","phoneNumber":"07221 39 85 70","email":"projektbewerbung@sps-cs.de"}
];

let contacts = fallbackContacts;

if (jsonString) {
  try {
    contacts = JSON.parse(jsonString);
  } catch(e) {
    console.log('JSON Parse Fehler:', e.message);
  }
}

return contacts.map(contact => ({
  json: {
    line: `${contact.fullName || ''}    ${contact.phoneNumber || ''}    ${contact.email || ''}`
  }
}));

const items = $input.all();
const plainText = items.map(item => item.json.line).join('\n');

return [{
  json: {
    text: plainText
  }
}];
